(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"pages-per-day",fields:[{"key":"totalPages","label":"전체 페이지","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"currentPage","label":"현재까지 읽은 페이지","type":"integer","placeholder":"","default":"0","options":[],"raw":false},{"key":"days","label":"남은 일수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var t=Number(x.totalPages),c=Number(x.currentPage),d=Number(x.days);if(!Number.isInteger(t)||!Number.isInteger(c)||!Number.isInteger(d)||t<0||c<0||c>t||d<=0)return{error:"페이지는 0 이상의 정수이며 현재 페이지는 전체 이하여야 하고 남은 일수는 1 이상이어야 합니다."};var rem=t-c;return{remaining:rem,perDay:rem/d,recommended:Math.ceil(rem/d)};},format:function(r,api){return api.resultCard("하루 권장 페이지",api.formatNumber(r.recommended,0)+"쪽","")+api.resultCard("정확한 일평균",api.formatNumber(r.perDay,2)+"쪽","")+api.resultCard("남은 페이지",api.formatNumber(r.remaining,0)+"쪽","");}},{id:"lecture-playback-time",fields:[{"key":"originalMinutes","label":"원본 강의시간 (분)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"speed","label":"재생배속","type":"number","placeholder":"","default":"1.5","options":[],"raw":false}],hint:"",compute:function(x){var m=Number(x.originalMinutes),s=Number(x.speed);if(![m,s].every(Number.isFinite)||m<0||s<=0)return{error:"강의시간은 0 이상, 재생배속은 0보다 크게 입력해 주세요."};var actual=m/s;return{minutes:actual,saved:m-actual};},format:function(r,api){var h=Math.floor(r.minutes/60),m=Math.round(r.minutes-h*60);return api.resultCard("실제 시청시간",h+"시간 "+m+"분","")+api.resultCard("절약되는 시간",api.formatNumber(r.saved,1)+"분","");}},{id:"pomodoro-plan",fields:[{"key":"targetFocus","label":"목표 집중시간 (분)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"focusLength","label":"1회 집중시간 (분)","type":"number","placeholder":"","default":"25","options":[],"raw":false},{"key":"breakLength","label":"세션 사이 휴식 (분)","type":"number","placeholder":"","default":"5","options":[],"raw":false}],hint:"",compute:function(x){var t=Number(x.targetFocus),f=Number(x.focusLength),b=Number(x.breakLength);if(![t,f,b].every(Number.isFinite)||t<0||f<=0||b<0)return{error:"목표시간은 0 이상, 집중시간은 0보다 크고 휴식시간은 0 이상이어야 합니다."};var sessions=t===0?0:Math.ceil(t/f),focus=sessions*f,breaks=Math.max(0,sessions-1)*b;return{sessions:sessions,plannedFocus:focus,totalMinutes:focus+breaks};},format:function(r,api){return api.resultCard("필요 세션",api.formatNumber(r.sessions,0)+"회","")+api.resultCard("전체 소요시간",api.formatNumber(r.totalMinutes,0)+"분","")+api.resultCard("계획 집중시간",api.formatNumber(r.plannedFocus,0)+"분","");}},{id:"study-plan-daily",fields:[{"key":"totalHours","label":"총 공부 목표시간 (시간)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"days","label":"남은 일수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var h=Number(x.totalHours),d=Number(x.days);if(!Number.isFinite(h)||h<0||!Number.isInteger(d)||d<=0)return{error:"총 공부시간은 0 이상, 남은 일수는 1 이상의 정수여야 합니다."};var daily=h/d;return{dailyHours:daily,dailyMinutes:daily*60};},format:function(r,api){return api.resultCard("하루 공부시간",api.formatNumber(r.dailyHours,2)+"시간","")+api.resultCard("분 환산",api.formatNumber(r.dailyMinutes,0)+"분","");}},{id:"allowed-absences",fields:[{"key":"totalClasses","label":"전체 수업 횟수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"requiredAttendance","label":"최소 출석률 (%)","type":"number","placeholder":"","default":"80","options":[],"raw":false}],hint:"학교·기관의 지각·조퇴 환산 규칙은 별도로 확인하세요.",compute:function(x){var t=Number(x.totalClasses),r=Number(x.requiredAttendance)/100;if(!Number.isInteger(t)||t<0||!Number.isFinite(r)||r<0||r>1)return{error:"수업 횟수는 0 이상의 정수, 출석률은 0~100%로 입력해 주세요."};var required=Math.ceil(t*r),abs=t-required;return{required:required,allowed:abs};},format:function(r,api){return api.resultCard("허용 가능한 최대 결석",api.formatNumber(r.allowed,0)+"회","")+api.resultCard("필요 출석 횟수",api.formatNumber(r.required,0)+"회","");}},{id:"grade-component-contribution",fields:[{"key":"score","label":"받은 점수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"maxScore","label":"만점","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"weight","label":"반영비율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.score),m=Number(x.maxScore),w=Number(x.weight);if(![s,m,w].every(Number.isFinite)||s<0||m<=0||s>m||w<0||w>100)return{error:"점수는 0 이상 만점 이하, 반영비율은 0~100%로 입력해 주세요."};var pct=s/m*100,contribution=s/m*w;return{percentage:pct,contribution:contribution};},format:function(r,api){return api.resultCard("최종성적 기여점수",api.formatNumber(r.contribution,2)+"점","")+api.resultCard("평가항목 득점률",api.formatNumber(r.percentage,2)+"%","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
